const response = $.steps.exaSearch.response || {};
const data = response.data || response;
const results = data.results || [];
const topN = $.input.scrapeTopN || 3;

const urls = results.slice(0, topN).map(r => r.url).filter(u => u);
const exaSummaries = results.slice(0, 8).map((r, i) => ({
  index: i + 1,
  title: r.title || 'Untitled',
  url: r.url || '',
  snippet: (r.text || r.snippet || '').slice(0, 500)
}));

return { urls, exaSummaries, totalResults: results.length };

const exa = $.steps.extractTopUrls.output;
const iterations = ($.steps.scrapePages.response || {}).iterations || [];

let allContent = 'EXA SEARCH RESULTS OVERVIEW:\n';
exa.exaSummaries.forEach(s => {
  allContent += s.index + '. ' + s.title + ' (' + s.url + ')\n   ' + s.snippet.slice(0, 300) + '\n\n';
});

allContent += '\nDEEP-SCRAPED CONTENT:\n';
const urls = exa.urls;
iterations.forEach((iter, i) => {
  const url = urls[i] || 'Unknown';
  const resp = (iter.scrapePage && iter.scrapePage.response && iter.scrapePage.response.data) ? iter.scrapePage.response.data : null;
  if (resp && resp.markdown) {
    allContent += '=== DEEP SCRAPE ' + (i + 1) + ' ===\n';
    allContent += 'URL: ' + url + '\n';
    allContent += resp.markdown.slice(0, 3000) + '\n\n';
  }
});

return { allContent: allContent.slice(0, 12000), sources: exa.exaSummaries };

const query = $.input.researchQuery;
const compiled = $.steps.compileResearch.output;

let prompt = 'You are a research analyst. Using the search results AND deep-scraped content below, produce a comprehensive research report on the given topic.

';
prompt += 'RESEARCH TOPIC: ' + query + '

';
prompt += 'GATHERED INTELLIGENCE:
' + compiled.allContent + '

';
prompt += 'INSTRUCTIONS:
';
prompt += '- Synthesize insights from both Exa search summaries and deep-scraped page content
';
prompt += '- Identify key themes, trends, and actionable findings
';
prompt += '- Note any conflicting information between sources
';
prompt += '- Provide concrete recommendations

';
prompt += 'Return ONLY valid JSON:
';
prompt += '{
';
prompt += '  "title": "Research Report Title",
';
prompt += '  "executiveSummary": "3-4 sentence high-level summary",
';
prompt += '  "keyFindings": ["finding1", "finding2", "finding3"],
';
prompt += '  "detailedAnalysis": "400-600 word analysis",
';
prompt += '  "recommendations": ["rec1", "rec2"],
';
prompt += '  "sourcesQuality": "high|medium|low",
';
prompt += '  "gaps": ["what could not be determined"]
';
prompt += '}';
return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { title: 'Research Report', executiveSummary: raw, keyFindings: [], detailedAnalysis: '', recommendations: [], sourcesQuality: 'unknown', gaps: [] }; }

const ai = $.steps.parseAI.output;
const sources = $.steps.compileResearch.output.sources;

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: (ai.title || 'Research Report').slice(0, 150), emoji: true } });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Sources Quality:*\n' + (ai.sourcesQuality || 'N/A') },
  { type: 'mrkdwn', text: '*Sources Analyzed:*\n' + (sources ? sources.length : 0) }
] });
blocks.push({ type: 'divider' });

const execSummary = (ai.executiveSummary || 'No summary generated.').slice(0, 1800);
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Executive Summary:*\n' + execSummary } });

if (ai.keyFindings && ai.keyFindings.length > 0) {
  blocks.push({ type: 'divider' });
  let kfText = '*Key Findings:*\n';
  ai.keyFindings.slice(0, 6).forEach((f, i) => { kfText += (i + 1) + '. ' + f + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: kfText.slice(0, 1800) } });
}

if (ai.detailedAnalysis) {
  blocks.push({ type: 'divider' });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Detailed Analysis:*\n' + ai.detailedAnalysis.slice(0, 1800) } });
}

if (ai.recommendations && ai.recommendations.length > 0) {
  blocks.push({ type: 'divider' });
  let recText = '*Recommendations:*\n';
  ai.recommendations.slice(0, 5).forEach((r, i) => { recText += (i + 1) + '. ' + r + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: recText.slice(0, 1800) } });
}

if (sources && sources.length > 0) {
  blocks.push({ type: 'divider' });
  let srcText = '*Sources:*\n';
  sources.slice(0, 5).forEach((s, i) => {
    srcText += (i + 1) + '. <' + s.url + '|' + (s.title || 'Source') + '>\n';
  });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: srcText.slice(0, 1800) } });
}

blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Powered by Exa + Firecrawl + Claude AI' }] });

const fallbackText = (ai.title || 'Research Report') + ': ' + (ai.executiveSummary || '').slice(0, 100);
return { blocks, fallbackText };
